function esc(v){return String(v??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;'}[m]))}
function lesson(t,txt,code,q,a,c=0,type='choice',expected=[]){return{t,txt,code,q,a,c,type,expected}}
function codeLesson(t,txt,code,q,expected){return lesson(t,txt,code,q,[],0,'code',expected)}
function matchLesson(t,txt,code,q,pairs){return{t,txt,code,q,type:'match',pairs}}function debugLesson(t,txt,broken,fixed,q){return{t,txt,code:broken,q,type:'debug',fixed}}
function shuffleList(arr){const a=[...arr];for(let i=a.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[a[i],a[j]]=[a[j],a[i]]}return a}
function getShuffledAnswers(l){return shuffleList(l.a.map((text,i)=>({text,correct:i===l.c})))}
