function addGeneratedUnits(){
  Object.keys(DATA).forEach(langKey=>{
    const lang = DATA[langKey];
    if (lang._generatedUnitsAdded) return;
    EXTRA_UNIT_TOPICS.forEach((topic, index)=>{
      const n = index + 1;
      lang.units.push({ name: `وحدة إضافية ${n}: ${topic[0]}`, lessons: makeUnitLessons(lang, topic, n) });
    });
    lang._generatedUnitsAdded = true;
  });
}
