  document.getElementById('icon-streak').innerHTML=ICONS.streak;
  document.getElementById('icon-done').innerHTML=ICONS.done;
  const titleMap={langs:'code',learn:'learn',profile:'profile',badges:'badge',scripts:'code',suggestions:'code',result:'badge',roadmap:'roadmap',quests:'quests',review:'review',speedrun:'speedrun',snippets:'code',practice:'practice',mistakes:'mistakes',projects:'projects',statsDetail:'statsDetail'};
