 if(name==='sounds')setProject('<h1>Sound Effects Lab</h1><button onclick="beep(220,\'sine\')">Low</button><button onclick="beep(440,\'square\')">Click</button><button onclick="win()">Win</button><button onclick="errorFx()">Error</button><button onclick="laser()">Laser</button><button onclick="coin()">Coin</button><button onclick="boom()">Explosion</button>','body{background:#050807;color:#00ff88;font-family:Arial;text-align:center;padding:40px}button{margin:8px;padding:18px 25px;border:0;border-radius:14px;background:#00ff88;font-weight:bold}','let ctx=new (AudioContext||webkitAudioContext)();function tone(f,d=.2,type="sine",v=.15){let o=ctx.createOscillator(),g=ctx.createGain();o.type=type;o.frequency.value=f;g.gain.value=v;o.connect(g);g.connect(ctx.destination);o.start();g.gain.exponentialRampToValueAtTime(.001,ctx.currentTime+d);o.stop(ctx.currentTime+d)}function beep(f,t){tone(f,.18,t)}function win(){[523,659,784,1046].forEach((f,i)=>setTimeout(()=>tone(f,.18,"sine"),i*90))}function errorFx(){tone(180,.35,"sawtooth",.12)}function laser(){let f=900;let id=setInterval(()=>{tone(f,.05,"square",.08);f-=80;if(f<160)clearInterval(id)},45)}function coin(){tone(880,.08);setTimeout(()=>tone(1320,.12),80)}function boom(){[90,70,50,40].forEach((f,i)=>setTimeout(()=>tone(f,.18,"sawtooth",.2),i*70))}');
 if(name==='clicker')setProject('<h1>Click Counter</h1><button id="btn" onclick="add()">Click</button><h2 id="count">0</h2>','body{background:#050807;color:#00ff88;font-family:Arial;text-align:center;padding:50px}button{font-size:24px;padding:25px 40px;border:0;border-radius:20px;background:#00ff88;font-weight:bold}h2{font-size:60px}','let n=0;function add(){n++;count.textContent=n;console.log("click",n)}');
 if(name==='reaction')setProject('<h1>Reaction Test</h1><button id="box" onclick="hit()">Wait...</button><p id="res"></p>','body{background:#050807;color:#00ff88;font-family:Arial;text-align:center;padding:40px}button{width:220px;height:120px;border:2px solid #00ff88;border-radius:20px;background:#07110d;color:#00ff88;font-size:24px;font-weight:bold}.ready{background:#00ff88!important;color:#001b0d!important}','let start=0;setTimeout(()=>{box.textContent="CLICK";box.classList.add("ready");start=Date.now()},1200+Math.random()*2000);function hit(){if(!start){res.textContent="Too early";return}res.textContent="Time: "+(Date.now()-start)+"ms"}');
