function resetCode(){defaultCode();runCode()}function clearConsole(){console.textContent='Console cleared.'}window.addEventListener('message',e=>{if(e.data&&e.data.type==='log')console.textContent+='\n'+e.data.msg});function saveScriptPrompt(){const name=prompt('اسم السكربت');if(!name)return;state.scripts.unshift({name,html:htmlEditor.value,css:cssEditor.value,js:jsEditor.value,at:Date.now()});state.scripts=state.scripts.slice(0,20);save();renderScripts();toast('تم حفظ السكربت')}function renderScripts(){scriptsList.innerHTML=state.scripts.length?state.scripts.map((s,i)=>`<div class="script-item"><b>${esc(s.name)}</b><div><button class="btn secondary" onclick="loadScript(${i})">فتح</button> <button class="btn secondary" onclick="renameScript(${i})">تسمية</button> <button class="btn danger" onclick="deleteScript(${i})">حذف</button></div></div>`).join(''):'<div class="small">لا توجد سكربتات محفوظة بعد.</div>'}function loadScript(i){const s=state.scripts[i];htmlEditor.value=s.html;cssEditor.value=s.css;jsEditor.value=s.js;runCode();showScreen('playground')}function deleteScript(i){state.scripts.splice(i,1);save();renderScripts()}function getAchievementDefs(){return [
 ['first','أول درس','أكمل أول درس',state.done.length>=1],
 ['five','خمسة دروس','أكمل 5 دروس',state.done.length>=5],
 ['twenty','عشرون درسًا','أكمل 20 درسًا',state.done.length>=20],
 ['xp100','مئة XP','اجمع 100 XP',state.xp>=100],
 ['script','حفظ سكربت','احفظ أول سكربت',state.scripts.length>=1],
 ['code','حل كتابة كود','أنهِ تمرين كتابة كود',(state.codeSolved||0)>=1],
 ['final','اختبار نهائي','اربح أول Boss Battle',state.finals.length>=1],
 ['master','ثلاثة اختبارات','اربح 3 Boss Battles',state.finals.length>=3],
 ['debugger','Bug Hunter','صحح أول تمرين Debug',(state.debugSolved||0)>=1],
 ['collector','Project Collector','احفظ 5 مشاريع',state.scripts.length>=5],
 ['speed','Speed Runner','اربح 20 نقطة في Speed/Practice',(state.xp||0)>=250],
 ['reviewer','Smart Reviewer','راجع 5 أخطاء',((state.correctAnswers||0)+(state.wrongAnswers||0))>=30],
 ['legend','Matrix Legend','اجمع 1000 XP',(state.xp||0)>=1000]
]}
function renderBadges(){const defs=getAchievementDefs();if(!document.getElementById('badgeGrid'))return;badgeGrid.innerHTML=defs.map(b=>`<div class="badge ${b[3]?'unlocked':''}">${ICONS.badge}<b>${b[1]}</b><div class="small">${b[3]?esc(b[2]):'مغلقة'}</div></div>`).join('')}
let achievementQueue=[],achievementShowing=false;
function checkAchievementUnlocks(){state.achievements??=[];const newly=[];getAchievementDefs().forEach(a=>{if(a[3]&&!state.achievements.includes(a[0])){state.achievements.push(a[0]);newly.push(a)}});if(newly.length){localStorage.setItem('codelingoState',JSON.stringify(state));newly.forEach(a=>achievementQueue.push(a));processAchievementQueue()}}
function processAchievementQueue(){if(achievementShowing||!achievementQueue.length)return;showMinecraftAchievement(achievementQueue.shift())}
function showMinecraftAchievement(a){achievementShowing=true;const old=document.querySelector('.mc-achievement');if(old)old.remove();const pop=document.createElement('div');pop.className='mc-achievement';pop.innerHTML=`<div class="mc-icon">${ICONS.badge}</div><div><div class="mc-label">Achievement Get!</div><div class="mc-title">${esc(a[1])}</div><div class="mc-desc">${esc(a[2])}</div></div>`;document.body.appendChild(pop);sound.unlock&&sound.unlock();requestAnimationFrame(()=>pop.classList.add('show'));setTimeout(()=>{pop.classList.remove('show');pop.classList.add('hide');setTimeout(()=>{pop.remove();achievementShowing=false;processAchievementQueue()},520)},3600)}
function toggleSound(){state.sound=!state.sound;save();toast(state.sound?'تم تشغيل الصوت':'تم إيقاف الصوت')}function resetProgress(){if(confirm('إعادة التقدم؟')){state={xp:0,done:[],finals:[],scripts:[],streak:1,sound:state.sound};save();renderLangs();renderScripts();toast('تمت الإعادة')}}
const _baseLoadTemplate = loadTemplate;
function fullProjectCode(){return `<!DOCTYPE html><html><head><meta charset="UTF-8"><title>CodeLingo Project</title><style>${cssEditor.value}</style></head><body>${htmlEditor.value}<scr`+`ipt>${jsEditor.value}</scr`+`ipt></body></html>`}
function copyFullCode(){navigator.clipboard&&navigator.clipboard.writeText(fullProjectCode());toast('تم نسخ الكود الكامل')}
function downloadProject(){const blob=new Blob([fullProjectCode()],{type:'text/html'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='codelingo-project.html';a.click();URL.revokeObjectURL(a.href);toast('تم تحميل ملف HTML')}
function renameScript(i){const n=prompt('اسم جديد',state.scripts[i].name);if(!n)return;state.scripts[i].name=n;save();renderScripts();toast('تمت إعادة التسمية')}
