 password:['<h1>Password Generator</h1><button onclick="gen()">Generate</button><h2 id="pass"></h2>','body{background:#050807;color:#00ff88;font-family:Arial;text-align:center;padding:40px}button{padding:15px 25px;border:0;border-radius:14px;background:#00ff88;font-weight:bold}h2{letter-spacing:2px}','function gen(){let chars="ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnpqrstuvwxyz23456789!@#$";pass.textContent=Array.from({length:14},()=>chars[Math.floor(Math.random()*chars.length)]).join("")}'],
