document.addEventListener('click',e=>{const target=e.target.closest('button,.lang-card,.lesson-card,.answer,.match-item');if(!target)return;if(target.closest('#playground')||target.classList.contains('tab'))return;const r=target.getBoundingClientRect();const sp=document.createElement('span');const size=Math.min(Math.max(r.width,r.height),120);sp.className='ripple';sp.style.width=sp.style.height=size+'px';sp.style.left=(e.clientX-r.left-size/2)+'px';sp.style.top=(e.clientY-r.top-size/2)+'px';target.appendChild(sp);setTimeout(()=>sp.remove(),360)});

// ===== Legendary FX runtime pack =====
state.effects ??= true;
function applyEffectsMode(){document.body.classList.toggle('effects-off',!state.effects);if(typeof effectsSwitch!=='undefined')effectsSwitch.classList.toggle('active',state.effects)}
function toggleEffects(){state.effects=!state.effects;save();applyEffectsMode();toast(state.effects?'تم تشغيل المؤثرات':'تم إيقاف المؤثرات')}
function fxLayer(){let l=document.querySelector('.fx-layer');if(!l){l=document.createElement('div');l.className='fx-layer';document.body.appendChild(l)}return l}
function codeParticles(x=innerWidth/2,y=innerHeight/2){if(!state.effects)return;const layer=fxLayer(),tokens=['{}','</>','=>','01','JS','CSS'];for(let i=0;i<10;i++){const p=document.createElement('span');p.className='code-particle';p.textContent=tokens[Math.floor(Math.random()*tokens.length)];p.style.left=x+'px';p.style.top=y+'px';p.style.setProperty('--x',(Math.random()*140-70)+'px');layer.appendChild(p);setTimeout(()=>p.remove(),950)}}
function xpFloat(v){if(!state.effects)return;const e=document.createElement('div');e.className='xp-float';e.textContent='+'+v+' XP';document.body.appendChild(e);setTimeout(()=>e.remove(),1000)}
