// ===== Keyboard sound + improved cyber click effects =====
sound.keyboard=function(){
  if(!state.sound)return;this.init();const ctx=this.ctx;if(!ctx)return;
  const dur=0.018+Math.random()*0.012;
  const buffer=ctx.createBuffer(1,Math.max(1,Math.floor(ctx.sampleRate*dur)),ctx.sampleRate);
  const data=buffer.getChannelData(0);
  for(let i=0;i<data.length;i++){const env=1-i/data.length;data[i]=(Math.random()*2-1)*env*.55}
  const src=ctx.createBufferSource();src.buffer=buffer;
  const hp=ctx.createBiquadFilter();hp.type='highpass';hp.frequency.value=900+Math.random()*500;
  const gain=ctx.createGain();gain.gain.value=0.010;
  src.connect(hp);hp.connect(gain);gain.connect(ctx.destination);src.start();
  const o=ctx.createOscillator(),g=ctx.createGain();o.type='triangle';o.frequency.value=1400+Math.random()*260;g.gain.value=0.006;o.connect(g);g.connect(ctx.destination);o.start();g.gain.exponentialRampToValueAtTime(.0001,ctx.currentTime+0.018);o.stop(ctx.currentTime+0.02);
};
