function startPracticeMix(){practiceQueue=shuffleList(Object.keys(DATA).flatMap(k=>allLessons(k))).slice(0,15);practiceIndex=0;practiceScore=0;showScreen('practice');renderPractice()}
function renderPractice(){
  if(practiceIndex>=practiceQueue.length){practiceQuestion.textContent='انتهت المراجعة المختلطة';practiceMeta.textContent=`نتيجتك ${practiceScore}/${practiceQueue.length}`;practiceArea.innerHTML=`<button class="btn" onclick="showScreen('home')">إنهاء</button>`;state.xp+=practiceScore*4;save();return}
  practiceCurrent=practiceQueue[practiceIndex];practiceMeta.textContent=`تمرين ${practiceIndex+1}/${practiceQueue.length} | Score ${practiceScore} | النوع ${practiceCurrent.type||'choice'}`;practiceQuestion.textContent=practiceCurrent.q;practiceFeedback.className='feedback';practiceFeedback.textContent='';
  if(practiceCurrent.type==='code'||practiceCurrent.type==='debug'){
    practiceArea.innerHTML=`<textarea class="write-editor" id="practiceInput" placeholder="اكتب الحل هنا"></textarea><button class="btn" style="margin-top:10px;width:100%" onclick="checkPracticeWrite()">تحقق</button>`;
  } else if(practiceCurrent.type==='match') {
    renderPracticeMatch();
  } else {
    const opts=getShuffledAnswers(practiceCurrent);practiceArea.innerHTML=`<div class="answers">${opts.map(o=>`<button class="answer" data-correct="${o.correct?'1':'0'}" onclick="practiceChoice(this)">${esc(o.text)}</button>`).join('')}</div>`;
  }
}
function practiceChoice(btn){if(btn.dataset.correct==='1'){practiceScore++;sound.success()}else sound.error();practiceIndex++;setTimeout(renderPractice,450)}
function checkPracticeWrite(){const q=practiceCurrent;const target=q.type==='debug'?q.fixed:q.code;const ok=normalizeCodeAnswer(practiceInput.value)===normalizeCodeAnswer(target);if(ok){practiceScore++;sound.success();practiceIndex++;setTimeout(renderPractice,450)}else{sound.error();practiceFeedback.className='feedback bad';practiceFeedback.textContent='حاول مرة أخرى أو اكتب الصيغة الصحيحة.'}}
function renderPracticeMatch(){const pairs=practiceCurrent.pairs||[];const left=shuffleList(pairs.map(p=>p[0]));const right=shuffleList(pairs.map(p=>p[1]));let matched=0,selected=null;practiceArea.innerHTML=`<div class="match-wrap"><div class="match-col"><div class="match-head">المفهوم</div>${left.map(x=>`<button class="match-item" data-side="left" data-value="${esc(x)}">${esc(x)}</button>`).join('')}</div><div class="match-col"><div class="match-head">المعنى</div>${right.map(x=>`<button class="match-item" data-side="right" data-value="${esc(x)}">${esc(x)}</button>`).join('')}</div></div>`;practiceArea.querySelectorAll('.match-item').forEach(btn=>btn.onclick=()=>{if(btn.classList.contains('matched'))return;if(!selected){selected=btn;btn.classList.add('selected');return}if(selected.dataset.side===btn.dataset.side){selected.classList.remove('selected');selected=btn;btn.classList.add('selected');return}const a=selected.dataset.side==='left'?selected.dataset.value:btn.dataset.value;const b=selected.dataset.side==='right'?selected.dataset.value:btn.dataset.value;const ok=pairs.some(p=>p[0]===a&&p[1]===b);if(ok){selected.classList.remove('selected');selected.classList.add('matched');btn.classList.add('matched');selected.disabled=true;btn.disabled=true;selected=null;matched++;sound.success();if(matched===pairs.length){practiceScore++;practiceIndex++;setTimeout(renderPractice,650)}}else{const prev=selected;btn.classList.add('wrong');prev.classList.add('wrong');sound.error();setTimeout(()=>{btn.classList.remove('wrong');prev.classList.remove('wrong')},450);prev.classList.remove('selected');selected=null}})}
function renderProjects(){if(!document.getElementById('projectsGrid'))return;projectsGrid.innerHTML=state.scripts.length?state.scripts.map((x,i)=>`<div class="project-card"><b>${esc(x.name)}</b><div class="small">${new Date(x.at||Date.now()).toLocaleString()}</div><span class="project-kind">${esc(x.kind||'مشروع')}</span><br><br><button class="btn secondary" onclick="loadScript(${i})">فتح</button> <button class="btn secondary" onclick="renameScript(${i})">تسمية</button> <button class="btn secondary" onclick="downloadSavedScript(${i})">تحميل</button> <button class="btn danger" onclick="deleteScript(${i});renderProjects()">حذف</button></div>`).join(''):'<div class="small">لا توجد مشاريع محفوظة بعد.</div>'}
function splitHTMLProject(text){
  const styles=[...text.matchAll(/<style[^>]*>([\s\S]*?)<\/style>/gi)].map(m=>m[1]).join('\n\n');
  const scripts=[...text.matchAll(/<script(?![^>]*src=)[^>]*>([\s\S]*?)<\/script>/gi)].map(m=>m[1]).join('\n\n');
  let body=text.match(/<body[^>]*>([\s\S]*?)<\/body>/i)?.[1] || text;
  body=body.replace(/<style[^>]*>[\s\S]*?<\/style>/gi,'').replace(/<script[^>]*>[\s\S]*?<\/script>/gi,'').replace(/<!doctype[^>]*>/i,'').replace(/<\/?html[^>]*>/gi,'').replace(/<head[^>]*>[\s\S]*?<\/head>/gi,'').trim();
  return {html:body,css:styles,js:scripts};
}
function projectFromFile(name,text){
  const lower=name.toLowerCase();
  if(lower.endsWith('.html')||lower.endsWith('.htm')){const parts=splitHTMLProject(text);return {name:name.replace(/\.[^.]+$/,''),kind:'HTML مرفوع',...parts};}
  if(lower.endsWith('.css'))return {name:name.replace(/\.[^.]+$/,''),kind:'CSS مرفوع',html:'<h1>CSS Uploaded</h1>\n<p>تم تحميل ملف CSS في المختبر.</p>',css:text,js:''};
  if(lower.endsWith('.js'))return {name:name.replace(/\.[^.]+$/,''),kind:'JS مرفوع',html:'<h1>JS Uploaded</h1>\n<button onclick="runUploaded()">Run</button>\n<p id="out"></p>',css:'body{font-family:Arial;background:#050807;color:#00ff88;text-align:center;padding:30px}button{background:#00ff88;border:0;border-radius:12px;padding:12px 18px;font-weight:bold}',js:text};
  return {name:name.replace(/\.[^.]+$/,'')||'uploaded-file',kind:'TXT مرفوع',html:`<pre>${esc(text)}</pre>`,css:'body{background:#050807;color:#00ff88;font-family:Consolas;padding:24px;white-space:pre-wrap}',js:''};
}

function getTopFolder(file){
  const rel=file.webkitRelativePath||file.name;
  return rel.includes('/') ? rel.split('/')[0] : '';
}
function importProjectFiles(files){
  const list=[...(files||[])];
  if(!list.length)return;
  const hasFolder=list.some(f=>f.webkitRelativePath&&f.webkitRelativePath.includes('/'));
  if(hasFolder) return importProjectFolder(list);
  list.forEach(file=>readSingleProjectFile(file));
}
function readFileText(file){
  return new Promise((resolve,reject)=>{
    const reader=new FileReader();
    reader.onload=()=>resolve(String(reader.result||''));
    reader.onerror=reject;
    reader.readAsText(file);
  });
}
function readSingleProjectFile(file){
  const reader=new FileReader();
  reader.onload=()=>{
    try{
      const project=projectFromFile(file.name,String(reader.result||''));
      addImportedProject(project);
    }catch(err){console.error(err);toast('تعذر قراءة الملف')}
  };
  reader.onerror=()=>toast('تعذر قراءة الملف');
  reader.readAsText(file);
}
function addImportedProject(project){
  state.scripts.unshift({...project,at:Date.now()});
  state.scripts=state.scripts.slice(0,20);
  save();renderScripts();renderProjects();
  htmlEditor.value=project.html;cssEditor.value=project.css;jsEditor.value=project.js;
  runCode();showScreen('playground');toast('تم رفع المشروع وتشغيله في المختبر');
}
async function importProjectFolder(files){
  try{
    const groups={};
    files.forEach(file=>{
      const top=getTopFolder(file)||'uploaded-folder';
      (groups[top]??=[]).push(file);
    });
    let firstProject=null;
    for(const [folder,group] of Object.entries(groups)){
      const project=await projectFromFolder(folder,group);
      state.scripts.unshift({...project,at:Date.now()});
      if(!firstProject) firstProject=project;
    }
    state.scripts=state.scripts.slice(0,20);
    save();renderScripts();renderProjects();
    if(firstProject){
      htmlEditor.value=firstProject.html;cssEditor.value=firstProject.css;jsEditor.value=firstProject.js;
      runCode();showScreen('playground');
    }
    toast(Object.keys(groups).length>1?'تم رفع المجلدات وتشغيل أول مشروع':'تم رفع المجلد وتشغيله في المختبر');
  }catch(err){console.error(err);toast('تعذر قراءة المجلد')}
}
async function projectFromFolder(folderName,files){
  const byName=(name)=>files.find(f=>(f.webkitRelativePath||f.name).toLowerCase().endsWith('/'+name)||f.name.toLowerCase()===name);
  const htmlFile=byName('index.html')||byName('index.htm')||files.find(f=>/\.html?$/i.test(f.name));
  const cssFiles=files.filter(f=>/\.css$/i.test(f.name));
  const jsFiles=files.filter(f=>/\.js$/i.test(f.name));
  let html='',css='',js='';
  if(htmlFile){
    const text=await readFileText(htmlFile);
    const parts=splitHTMLProject(text);
    html=parts.html; css=parts.css; js=parts.js;
  }else{
    html='<h1>'+esc(folderName)+'</h1>\n<p>تم رفع مجلد مشروع بدون index.html</p>';
  }
  for(const f of cssFiles){ css += '\n\n/* '+(f.webkitRelativePath||f.name)+' */\n' + await readFileText(f); }
  for(const f of jsFiles){ js += '\n\n// '+(f.webkitRelativePath||f.name)+'\n' + await readFileText(f); }
  const txtFiles=files.filter(f=>/\.txt$/i.test(f.name));
  if(!htmlFile && txtFiles.length){
    const text=await readFileText(txtFiles[0]);
    html='<pre>'+esc(text)+'</pre>';
    css+='\nbody{background:#050807;color:#00ff88;font-family:Consolas;padding:24px;white-space:pre-wrap}';
  }
  return {name:folderName,kind:'مجلد مرفوع',html,css,js};
}
function toggleFocusMode(){document.body.classList.toggle('focus-mode');toast(document.body.classList.contains('focus-mode')?'Focus Mode مفعل':'Focus Mode متوقف')}function logoutUser(){localStorage.removeItem(USER_KEY);toast('تم تسجيل الخروج');setTimeout(()=>location.reload(),650)}
const _showScreenMore=showScreen;showScreen=function(id){const r=_showScreenMore(id);if(id==='mistakes')renderMistakesLibrary();if(id==='projects')renderProjects();if(id==='statsDetail'){renderLevel();renderDetailedStats()}if(id==='quests')updateDailyUI();if(id==='roadmap')renderRoadmap();if(id==='review')renderReview();return r};

// ===== Robust lesson start fix: reliable click/touch/keyboard entry =====
function safeStartLessonFromCard(card){
  if(!card) return;
  const k=card.dataset.lang;
  const ui=Number(card.dataset.ui);
  const li=Number(card.dataset.li);
  if(card.dataset.locked==='1') { toast('أكمل الدرس السابق أولاً'); return; }
  if(!DATA[k] || !DATA[k].units?.[ui] || !DATA[k].units[ui].lessons?.[li]) { toast('تعذر فتح التمرين'); return; }
  try { openLesson(k,ui,li); }
  catch(err){ console.error(err); toast('حدث خطأ أثناء فتح التمرين'); }
}
document.addEventListener('click', function(e){
  const card=e.target.closest('.lesson-card[data-lang]');
  if(!card) return;
  e.preventDefault();
  e.stopPropagation();
  safeStartLessonFromCard(card);
}, true);
document.addEventListener('keydown', function(e){
  if((e.key==='Enter'||e.key===' ') && e.target.matches('.lesson-card[data-lang]')){
    e.preventDefault();
    safeStartLessonFromCard(e.target);
  }
});

